type entry struct {
    Case      string `json:"case"`
    Produced  []int  `json:"produced"`
    Trace     []int  `json:"slot_trace"`
    OrderUsed []int  `json:"order_used"`
    Packed    bool   `json:"packed"`
    Grouped   bool   `json:"grouped"`
    Reuse     bool   `json:"reuse"`
}

type rawDoc struct {
    Raw []entry `json:"raw"`
}

type finalDoc struct {
    Rows    []entry        `json:"rows"`
    Summary map[string]any `json:"summary"`
}

func loadJSON(path string, dst any) error {
    buf, err := os.ReadFile(path)
    if err != nil {
        return err
    }
    return json.Unmarshal(buf, dst)
}

func loadSets(path string) ([]string, error) {
    buf, err := os.ReadFile(path)
    if err != nil {
        return nil, err
    }
    lines := strings.Split(string(buf), "\n")
    out := make([]string, 0, len(lines))
    for _, ln := range lines {
        ln = strings.TrimSpace(ln)
        if ln == "" {
            continue
        }
        out = append(out, ln)
    }
    return out, nil
}

func keyByCase(rows []entry) map[string]entry {
    m := make(map[string]entry, len(rows))
    for _, r := range rows {
        m[r.Case] = r
    }
    return m
}

func eqEntry(a, b entry) bool {
    if a.Case != b.Case || a.Packed != b.Packed || a.Grouped != b.Grouped || a.Reuse != b.Reuse {
        return false
    }
    if len(a.Produced) != len(b.Produced) || len(a.Trace) != len(b.Trace) || len(a.OrderUsed) != len(b.OrderUsed) {
        return false
    }
    for i := range a.Produced {
        if a.Produced[i] != b.Produced[i] {
            return false
        }
    }
    for i := range a.Trace {
        if a.Trace[i] != b.Trace[i] {
            return false
        }
    }
    for i := range a.OrderUsed {
        if a.OrderUsed[i] != b.OrderUsed[i] {
            return false
        }
    }
    return true
}

func main() {
    if len(os.Args) != 3 {
        panic("usage: align raw final")
    }

    rawPath := os.Args[1]
    outPath := os.Args[2]

    var raw rawDoc
    if err := loadJSON(rawPath, &raw); err != nil {
        panic(err)
    }

    // Produce final rows deterministically: one row per built-in case in sets.txt.
    // The report row shape matches raw entry and produced MUST equal raw produced.
    sets, err := loadSets("/app/config/sets.txt")
    if err != nil {
        panic(err)
    }
    rawBy := keyByCase(raw.Raw)

    rows := make([]entry, 0, len(sets))
    for _, name := range sets {
        r, ok := rawBy[name]
        if !ok {
            // Do not silently drop: missing cases should break agreement.
            continue
        }
        rows = append(rows, r)
    }

    // Agreement checks:
    // 1) new report rows vs incoming raw rows (per case, on the six fields).
    // 2) if prior report exists at outPath, compare its rows vs incoming raw rows too;
    //    any mismatch forces agree=false even if new rows match.
    agree := true

    // Ensure we cover all cases exactly once.
    if len(rows) != len(sets) || len(raw.Raw) != len(sets) {
        agree = false
    }

    // Compare new rows to incoming raw by case.
    newBy := keyByCase(rows)
    for _, name := range sets {
        ra, okA := rawBy[name]
        rb, okB := newBy[name]
        if !okA || !okB {
            agree = false
            continue
        }
        if !eqEntry(ra, rb) {
            agree = false
        }
    }

    // Compare prior report (if any) to incoming raw by case.
    var prior finalDoc
    if err := loadJSON(outPath, &prior); err == nil {
        priorBy := keyByCase(prior.Rows)
        for _, name := range sets {
            ra, okA := rawBy[name]
            rp, okP := priorBy[name]
            if !okA || !okP {
                agree = false
                continue
            }
            if !eqEntry(ra, rp) {
                agree = false
            }
        }
    }

    doc := finalDoc{Rows: rows, Summary: map[string]any{"total": len(sets), "agree": agree}}
    out, err := json.MarshalIndent(doc, "", "  ")
    if err != nil {
        panic(err)
    }
    if err := os.WriteFile(outPath, append(out, '\n'), 0o644); err != nil {
        panic(err)
    }

    _ = fmt.Sprintf("")
}
